  'type' => 'function',
  'function' => 
  array (
    'name' => 'scatter_gather',
    'description' => 'Scatter-gather research pipeline: queries Wikipedia, GitHub, and Packagist for a topic, then persists all results to a SQLite database for later retrieval. Returns a consolidated report with findings from all sources and database storage confirmation. Uses PHP streams for HTTP, json_decode for API parsing, and PDO_SQLite for persistence. Three-domain composition (network + APIs + database) — genuinely new cross-capability tool.',
    'parameters' => 
    array (
      'type' => 'object',
      'properties' => 
      array (
        'topic' => 
        array (
          'type' => 'string',
          'description' => 'The topic to research.',
        ),
        'db_name' => 
        array (
          'type' => 'string',
          'description' => 'SQLite database filename (stored in workspace). Default: \'research.sqlite\'.',
        ),
        'timeout' => 
        array (
          'type' => 'integer',
          'description' => 'Timeout per source in seconds (5-30, default 15).',
        ),
        'max_results' => 
        array (
          'type' => 'integer',
          'description' => 'Max results per source (1-10, default 5).',
        ),
      ),
