      array (
        0 => 'topic',
      ),
    ),
  ),
);

if (! function_exists('scatter_gather')) {
    function scatter_gather($topic, $db_name = null, $timeout = null, $max_results = null)
    {
        $topic = isset($topic) ? trim($topic) : '';
        if ($topic === '') {
            return ['error' => 'Topic is required.', 'report' => null];
        }

        $db_name = isset($db_name) && is_string($db_name) && $db_name !== '' ? $db_name : 'research.sqlite';
        $timeout = isset($timeout) ? max(5, min(30, (int)$timeout)) : 15;
        $max_results = isset($max_results) ? max(1, min(10, (int)$max_results)) : 5;

        $start_time = microtime(true);

        // ---- Helper: fetch URL ----
        $fetch = function($url, $timeout_sec) {
            $ctx = stream_context_create([
                'http' => ['method' => 'GET', 'header' => 'User-Agent: self-bootstrapping-agent/1.0', 'timeout' => $timeout_sec, 'ignore_errors' => true],
                'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
            ]);
            $err = null;
            set_error_handler(function($s, $m) use (&$err) { $err = $m; return true; });
            $body = @file_get_contents($url, false, $ctx);
            $headers = $http_response_header ?? [];
            restore_error_handler();
            $status = 0;
            foreach ($headers as $i => $h) {
                if ($i === 0 && preg_match('#HTTP/\d+\.\d+ (\d+)#', $h, $m)) { $status = (int)$m[1]; break; }
            }
            return ['status' => $status, 'body' => $body, 'error' => $err, 'headers' => $headers];
        };

        $sources = [];
        $errors = [];
        $all_findings = [];

        // ---- Source 1: Wikipedia ----
        $wiki_safe = str_replace(' ', '_', $topic);
        $wiki_url = 'https://en.wikipedia.org/w/api.php?action=query&titles=' . rawurlencode($wiki_safe) . '&prop=extracts|info&exintro=true&explaintext=true&format=json&redirects=1';
        $wiki_resp = $fetch($wiki_url, $timeout);

        $wiki = ['source' => 'Wikipedia', 'status' => 0, 'title' => null, 'extract' => null, 'page_id' => null, 'error' => null];

        if ($wiki_resp['body'] === false) {
            $wiki['error'] = $wiki_resp['error'] ?? 'Failed';
            $errors[] = 'Wikipedia: ' . $wiki['error'];
        } else {
            $wiki['status'] = $wiki_resp['status'];
            $data = json_decode($wiki_resp['body'], true);
            if ($data && isset($data['query']['pages'])) {
                foreach ($data['query']['pages'] as $id => $page) {
                    if ($id === '-1') {
                        $wiki['error'] = 'Page not found';
                    } else {
                        $wiki['title'] = $page['title'] ?? null;
                        $wiki['page_id'] = (int)$id;
                        $extract = $page['extract'] ?? '';
                        $wiki['extract'] = mb_strlen($extract) > 3000 ? mb_substr($extract, 0, 3000) . '...' : $extract;
                    }
                    break;
                }
            } else {
                $wiki['error'] = 'Parse failed';
            }
        }

        if ($wiki['title']) {
            $all_findings[] = ['source' => 'Wikipedia', 'key' => $wiki['title'], 'value' => mb_substr($wiki['extract'] ?? '', 0, 500)];
        }

        // ---- Source 2: GitHub ----
        $github_url = 'https://api.github.com/search/repositories?q=' . rawurlencode($topic . '+language:php') . '&sort=stars&order=desc&per_page=' . $max_results;
        $gh_resp = $fetch($github_url, $timeout);

        $github = ['source' => 'GitHub', 'status' => 0, 'total_count' => 0, 'repos' => [], 'error' => null];

        if ($gh_resp['body'] === false) {
            $github['error'] = $gh_resp['error'] ?? 'Failed';
            $errors[] = 'GitHub: ' . $github['error'];
        } else {
            $github['status'] = $gh_resp['status'];
            $data = json_decode($gh_resp['body'], true);
            if ($data && isset($data['items'])) {
                $github['total_count'] = $data['total_count'] ?? 0;
                foreach ($data['items'] as $repo) {
                    $r = [
                        'name' => $repo['full_name'] ?? '',
                        'stars' => $repo['stargazers_count'] ?? 0,
                        'description' => $repo['description'] ?? '',
                        'url' => $repo['html_url'] ?? '',
                        'forks' => $repo['forks_count'] ?? 0,
                        'language' => $repo['language'] ?? '',
                    ];
                    $github['repos'][] = $r;
                    $all_findings[] = ['source' => 'GitHub', 'key' => $r['name'], 'value' => $r['description'] . ' (' . $r['stars'] . ' stars)'];
                }
            } else {
                $github['error'] = 'Parse failed';
            }
        }

        // Extract rate limit
        foreach ($gh_resp['headers'] as $h) {
            if (stripos($h, 'x-ratelimit-remaining:') === 0) {
                $github['rate_limit_remaining'] = (int)trim(substr($h, 21));
            }
        }

        // ---- Source 3: Packagist ----
        $packagist_url = 'https://packagist.org/search.json?q=' . rawurlencode($topic) . '&per_page=' . $max_results;
        $pkg_resp = $fetch($packagist_url, $timeout);

        $packagist = ['source' => 'Packagist', 'status' => 0, 'total' => 0, 'packages' => [], 'error' => null];

        if ($pkg_resp['body'] === false) {
            $packagist['error'] = $pkg_resp['error'] ?? 'Failed';
            $errors[] = 'Packagist: ' . $packagist['error'];
        } else {
            $packagist['status'] = $pkg_resp['status'];
            $data = json_decode($pkg_resp['body'], true);
            if ($data && isset($data['results'])) {
                $packagist['total'] = $data['total'] ?? 0;
                foreach ($data['results'] as $pkg) {
                    $p = [
                        'name' => $pkg['name'] ?? '',
                        'description' => $pkg['description'] ?? '',
                        'url' => $pkg['url'] ?? '',
                        'downloads' => $pkg['downloads'] ?? 0,
                        'favers' => $pkg['favers'] ?? 0,
                    ];
                    $packagist['packages'][] = $p;
                    $all_findings[] = ['source' => 'Packagist', 'key' => $p['name'], 'value' => $p['description'] . ' (' . number_format($p['downloads']) . ' downloads)'];
                }
            } else {
                $packagist['error'] = 'Parse failed';
            }
        }

        $sources = ['wikipedia' => $wiki, 'github' => $github, 'packagist' => $packagist];

        // ---- Step 4: Persist to SQLite ----
        $db_dir = getcwd() . '/storage/agent/workspace';
        $db_path = $db_dir . '/' . $db_name;
        if (!str_ends_with($db_path, '.sqlite')) $db_path .= '.sqlite';
        if (!is_dir($db_dir)) @mkdir($db_dir, 0755, true);

        $db_save_result = null;
        $db_error = null;

        try {
            $pdo = new PDO('sqlite:' . $db_path);
            $pdo->setAttribute(PDO::ATTR_ERRMODE, PDO::ERRMODE_EXCEPTION);
            $pdo->exec('PRAGMA journal_mode=WAL');
            
            // Create tables if they don't exist
            $pdo->exec('CREATE TABLE IF NOT EXISTS research_runs (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                topic TEXT NOT NULL,
                timestamp TEXT DEFAULT (datetime(\'now\')),
                sources_ok INTEGER DEFAULT 0,
                total_findings INTEGER DEFAULT 0
            )');
            $pdo->exec('CREATE TABLE IF NOT EXISTS research_findings (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                run_id INTEGER NOT NULL,
                source TEXT NOT NULL,
                key_name TEXT NOT NULL,
                value TEXT,
                FOREIGN KEY (run_id) REFERENCES research_runs(id)
            )');
            
            // Insert the run
            $sources_ok = 0;
            if ($wiki['title']) $sources_ok++;
            if ($github['total_count'] > 0) $sources_ok++;
            if ($packagist['total'] > 0) $sources_ok++;
            
            $stmt = $pdo->prepare('INSERT INTO research_runs (topic, sources_ok, total_findings) VALUES (?, ?, ?)');
            $stmt->execute([$topic, $sources_ok, count($all_findings)]);
            $run_id = $pdo->lastInsertId();
            
            // Insert findings
            $ins = $pdo->prepare('INSERT INTO research_findings (run_id, source, key_name, value) VALUES (?, ?, ?, ?)');
            foreach ($all_findings as $f) {
                $ins->execute([$run_id, $f['source'], $f['key'], mb_substr($f['value'], 0, 2000)]);
            }
            
            $db_save_result = [
                'db' => $db_name,
                'db_path' => 'storage/agent/workspace/' . $db_name,
                'run_id' => (int)$run_id,
                'findings_stored' => count($all_findings),
            ];
        } catch (\Exception $e) {
            $db_error = $e->getMessage();
        }

        $elapsed = round(microtime(true) - $start_time, 2);

        // ---- Build consolidated report ----
        $sources_report = [];
        if ($wiki['title']) $sources_report[] = 'Wikipedia: "' . $wiki['title'] . '" (' . mb_strlen($wiki['extract'] ?? '') . ' chars)';
        if ($github['total_count'] > 0) $sources_report[] = 'GitHub: ' . $github['total_count'] . ' repos';
        if ($packagist['total'] > 0) $sources_report[] = 'Packagist: ' . $packagist['total'] . ' packages';

        $consolidated = 'Researched "' . $topic . '" from ';
        if (!empty($sources_report)) {
            $consolidated .= implode(', ', $sources_report) . '. ';
        }
        $consolidated .= 'Found ' . count($all_findings) . ' total findings.';
        if ($db_save_result) {
            $consolidated .= ' Stored to database (run #' . $db_save_result['run_id'] . ').';
        }

        return [
            'error' => !empty($errors) ? implode('; ', $errors) : null,
            'topic' => $topic,
            'consolidated' => $consolidated,
            'timing_seconds' => $elapsed,
            'sources' => $sources,
            'findings_count' => count($all_findings),
            'findings' => $all_findings,
            'database' => $db_save_result,
            'db_error' => $db_error,
        ];
    }
}
